import{_ as e,o as a,c as l,ag as i}from"./chunks/framework-C5-Jzrz4.js";const o=JSON.parse('{"title":"本地开发与联调","description":"web-antd 本地启动、环境变量与代理联调流程","frontmatter":{"title":"本地开发与联调","description":"web-antd 本地启动、环境变量与代理联调流程"},"headers":[],"relativePath":"scripts/development/本地开发与联调.md","filePath":"scripts/development/本地开发与联调.md","lastUpdated":null}');const t=e({name:"scripts/development/本地开发与联调.md"},[["render",function(e,o,t,d,c,r){return a(),l("div",null,[...o[0]||(o[0]=[i('<h1 id="本地开发与联调" tabindex="-1">本地开发与联调 <a class="header-anchor" href="#本地开发与联调" aria-label="Permalink to &quot;本地开发与联调&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页说明 <code>web-antd</code> 在本地联调时的最小流程，包含环境变量和代理路径的确认点。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>本地首次启动</li><li>前后端联调</li><li>请求路径异常排查</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/.env*</code></li><li><code>apps/web-antd/vite.config.ts</code></li><li><code>packages/effects/hooks/src/use-app-config.ts</code></li><li><code>apps/web-antd/src/utils/http/index.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="启动步骤" tabindex="-1">启动步骤 <a class="header-anchor" href="#启动步骤" aria-label="Permalink to &quot;启动步骤&quot;">​</a></h3><ol><li>安装依赖：<code>pnpm install</code></li><li>启动主应用：<code>pnpm dev:antd</code></li><li>默认访问：<code>http://localhost:5666</code>（来自 <code>.env.development</code> 的 <code>VITE_PORT</code>）</li></ol><h3 id="联调关键配置" tabindex="-1">联调关键配置 <a class="header-anchor" href="#联调关键配置" aria-label="Permalink to &quot;联调关键配置&quot;">​</a></h3><ul><li><code>VITE_GLOB_API_URL</code>： <ul><li>直接写后端地址时，请求走该地址</li><li>写相对路径时通常配合 Vite 代理</li></ul></li><li>Vite 代理（<code>vite.config.ts</code>）： <ul><li><code>/api -&gt; http://localhost:8080</code></li><li><code>rewrite: ^/api -&gt; &#39;&#39;</code></li><li><code>ws: true</code></li></ul></li></ul><h3 id="请求头与语言" tabindex="-1">请求头与语言 <a class="header-anchor" href="#请求头与语言" aria-label="Permalink to &quot;请求头与语言&quot;">​</a></h3><p>请求层会自动注入：</p><ul><li><code>Authorization</code></li><li><code>ClientID</code></li><li><code>Accept-Language</code></li><li><code>Content-Language</code></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>若接口 404，先确认是否走了 <code>/api</code> 代理，还是直接请求了 <code>VITE_GLOB_API_URL</code>。</li><li>若后端要求加密，请确认 <code>VITE_GLOB_ENABLE_ENCRYPT</code> 和密钥配置是否匹配。</li><li>若切换了 <code>preferences</code> 或关键环境变量，建议清理浏览器缓存后再验证。</li></ul>',17)])])}]]);export{o as __pageData,t as default};
